choice = input("Enter choice (1-12) to print month: ")

# Perform calculation
if choice == '1':
    print("Month - January")

elif choice == '2':
    print("Month - February")

elif choice == '3':
    print("Month - March")

elif choice == '4':
    print("Month - April")

elif choice == '5':
    print("Month - May")

elif choice == '6':
    print("Month - June")

elif choice == '7':
    print("Month - July")

elif choice == '8':
    print("Month - August")

elif choice == '9':
    print("Month - September")

elif choice == '10':
    print("Month - October")

elif choice == '11':
    print("Month - November")

elif choice == '12':
    print("Month - December")

else:
    print("Invalid input")

    


